(SELECT patient_id, resource FROM "Encounter With Abnormal Presentation") UNION (SELECT patient_id, resource FROM "Encounter With Genital Herpes, Placenta Previa, Vasa Previa Or Placenta Accreta Spectrum")
),
"Denominator Exclusions" AS (
SELECT * FROM "Delivery Encounter With Abnormal Presentation, Genital Herpes, Placenta Previa, Vasa Previa Or Placenta Accreta Spectrum"
),
"Numerator" AS (
SELECT * FROM "Delivery Encounter With Cesarean Birth"
)
SELECT p.patient_id, (SELECT COALESCE(LIST(json_extract_string("Initial Population".resource, '$.resourceType') || '/' || json_extract_string("Initial Population".resource, '$.id')), []) FROM "Initial Population" WHERE "Initial Population".patient_id = p.patient_id AND "Initial Population".resource IS NOT NULL) AS "Initial Population", (SELECT COALESCE(LIST(json_extract_string("Denominator".resource, '$.resourceType') || '/' || json_extract_string("Denominator".resource, '$.id')), []) FROM "Denominator" WHERE "Denominator".patient_id = p.patient_id AND "Denominator".resource IS NOT NULL) AS Denominator, (SELECT COALESCE(LIST(json_extract_string("Denominator Exclusions".resource, '$.resourceType') || '/' || json_extract_string("Denominator Exclusions".resource, '$.id')), []) FROM "Denominator Exclusions" WHERE "Denominator Exclusions".patient_id = p.patient_id AND "Denominator Exclusions".resource IS NOT NULL) AS "Denominator Exclusions", (SELECT COALESCE(LIST(json_extract_string("Numerator".resource, '$.resourceType') || '/' || json_extract_string("Numerator".resource, '$.id')), []) FROM "Numerator" WHERE "Numerator".patient_id = p.patient_id AND "Numerator".resource IS NOT NULL) AS Numerator FROM _patients p ORDER BY p.patient_id ASC
